import{_ as e,c as a,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"OpenAI 할당량 조회: 3시간/24시간 창 | opencode-mystatus","description":"OpenAI ChatGPT의 3시간 및 24시간 할당량 조회 방법을 학습합니다. 메인 창, 서브 창 해석과 토큰 만료 처리 방법을 마스터합니다.","frontmatter":{"title":"OpenAI 할당량 조회: 3시간/24시간 창 | opencode-mystatus","sidebarTitle":"OpenAI 할당량","subtitle":"OpenAI 할당량 조회: 3시간 및 24시간 할당량","description":"OpenAI ChatGPT의 3시간 및 24시간 할당량 조회 방법을 학습합니다. 메인 창, 서브 창 해석과 토큰 만료 처리 방법을 마스터합니다.","tags":["OpenAI","할당량 조회","API 할당량"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"ko/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"ko/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),i={name:"ko/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function n(s,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="openai-할당량-조회-3시간-및-24시간-할당량" tabindex="-1">OpenAI 할당량 조회: 3시간 및 24시간 할당량 <a class="header-anchor" href="#openai-할당량-조회-3시간-및-24시간-할당량" aria-label="Permalink to &quot;OpenAI 할당량 조회: 3시간 및 24시간 할당량&quot;">​</a></h1><h2 id="학습-후-할-수-있는-것" tabindex="-1">학습 후 할 수 있는 것 <a class="header-anchor" href="#학습-후-할-수-있는-것" aria-label="Permalink to &quot;학습 후 할 수 있는 것&quot;">​</a></h2><ul><li><code>/mystatus</code>를 사용하여 OpenAI Plus/Team/Pro 구독 할당량 조회</li><li>출력에서의 3시간 및 24시간 할당량 정보 이해</li><li>메인 창과 서브 창의 차이 이해</li><li>토큰 만료 시의 처리 방법 이해</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p>OpenAI의 API 호출은 할당량이 있으며, 초과 후 일시적으로 접근이 제한됩니다. 하지만 다음을 모릅니다:</p><ul><li>현재 남은 할당량이 얼마인가?</li><li>3시간 및 24시간 창 중 어느 것이 사용 중인가?</li><li>언제 재설정되는가?</li><li>때로 두 창의 데이터가 보이는 이유는?</li></ul><p>이 정보를 제때 파악하지 못하면 ChatGPT를 사용하여 코드를 작성하거나 프로젝트를 진행하는 데 영향을 줄 수 있습니다.</p><h2 id="언제-이-기능을-사용하나요" tabindex="-1">언제 이 기능을 사용하나요? <a class="header-anchor" href="#언제-이-기능을-사용하나요" aria-label="Permalink to &quot;언제 이 기능을 사용하나요?&quot;">​</a></h2><p>다음 경우에:</p><ul><li>OpenAI API를 자주 사용하여 개발</li><li>응답 속도가 느려지거나 플로우 제한을 겪을 때</li><li>팀 계정의 사용 상황을 알고 싶을 때</li><li>할당량이 언제 새로고침되는지 알고 싶을 때</li></ul><h2 id="핵심-원리" tabindex="-1">핵심 원리 <a class="header-anchor" href="#핵심-원리" aria-label="Permalink to &quot;핵심 원리&quot;">​</a></h2><p>OpenAI는 API 호출에 대해 두 가지 플로우 제한 창이 있습니다:</p><table tabindex="0"><thead><tr><th>창 유형</th><th>시간</th><th>역할</th></tr></thead><tbody><tr><td><strong>메인 창</strong>(primary)</td><td>OpenAI 서버에서 반환됨</td><td>단기간에 대량의 호출 방지</td></tr><tr><td><strong>서브 창</strong>(secondary)</td><td>OpenAI 서버에서 반환됨(존재하지 않을 수 있음)</td><td>장기간 초과 사용 방지</td></tr></tbody></table><p>mystatus는 이 두 창을 병렬로 조회하여, 각각의 다음을 표시합니다:</p><ul><li>사용된 백분율</li><li>남은 할당량 프로그레스 바</li><li>재설정까지 남은 시간</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>창 시간은 OpenAI 서버에서 반환되며, 다른 구독 유형(Plus, Team, Pro)은 다를 수 있습니다.</p></div><h2 id="따라하기" tabindex="-1">따라하기 <a class="header-anchor" href="#따라하기" aria-label="Permalink to &quot;따라하기&quot;">​</a></h2><h3 id="_1단계-조회-명령어-실행" tabindex="-1">1단계: 조회 명령어 실행 <a class="header-anchor" href="#_1단계-조회-명령어-실행" aria-label="Permalink to &quot;1단계: 조회 명령어 실행&quot;">​</a></h3><p>OpenCode에서 <code>/mystatus</code>를 입력하면, 시스템이 자동으로 모든 설정된 플랫폼의 할당량을 조회합니다.</p><p><strong>다음과 같이 보여야 합니다</strong>: 설정된 모든 플랫폼(OpenAI, 지푸 AI, Z.ai, Copilot, Google Cloud 등)의 할당량 정보가 포함됩니다(어떤 플랫폼을 설정했는지에 따름).</p><h3 id="_2단계-openai-부분-찾기" tabindex="-1">2단계: OpenAI 부분 찾기 <a class="header-anchor" href="#_2단계-openai-부분-찾기" aria-label="Permalink to &quot;2단계: OpenAI 부분 찾기&quot;">​</a></h3><p>출력에서 <code>## OpenAI Account Quota</code> 부분을 찾으세요.</p><p><strong>다음과 같이 보여야 합니다</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="_3단계-메인-창-정보-해석" tabindex="-1">3단계: 메인 창 정보 해석 <a class="header-anchor" href="#_3단계-메인-창-정보-해석" aria-label="Permalink to &quot;3단계: 메인 창 정보 해석&quot;">​</a></h3><p><strong>메인 창</strong>(primary_window)은 일반적으로 다음을 표시합니다:</p><ul><li><strong>창 이름</strong>: 예: <code>3-hour limit</code> 또는 <code>24-hour limit</code></li><li><strong>프로그레스 바</strong>: 남은 할당량 비율을 직관적으로 표시</li><li><strong>남은 백분율</strong>: 예: <code>60% remaining</code></li><li><strong>재설정 시간</strong>: 예: <code>Resets in: 2h 30m</code></li></ul><p><strong>다음과 같이 보여야 합니다</strong>:</p><ul><li>창 이름에 시간이 표시됨(3시간 / 24시간)</li><li>프로그레스 바가 가득 찼을수록 남은 것이 많고, 비었을수록 곧 다 사용됨</li><li>재설정 시간은 카운트다운으로, 0이 되면 할당량이 새로고침됨</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>Limit reached!</code>가 표시되면, 현재 창 할당량이 다 사용된 것이며, 재설정을 기다려야 합니다.</p></div><h3 id="_4단계-서브-창-확인-있다면" tabindex="-1">4단계: 서브 창 확인(있다면) <a class="header-anchor" href="#_4단계-서브-창-확인-있다면" aria-label="Permalink to &quot;4단계: 서브 창 확인(있다면)&quot;">​</a></h3><p>OpenAI가 서브 창 데이터를 반환하면 다음을 볼 수 있습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>다음과 같이 보여야 합니다</strong>:</p><ul><li>서브 창은 다른 시간 차원의 할당량을 표시합니다(일반적으로 24시간)</li><li>메인 창과 다른 남은 백분율을 가질 수 있음</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>서브 창은 독립적인 할당량 풀로, 메인 창이 사용해도 서브 창에 영향을 주지 않으며, 그 반대도 마찬가지입니다.</p></div><h3 id="_5단계-구독-유형-확인" tabindex="-1">5단계: 구독 유형 확인 <a class="header-anchor" href="#_5단계-구독-유형-확인" aria-label="Permalink to &quot;5단계: 구독 유형 확인&quot;">​</a></h3><p><code>Account</code> 행에서 구독 유형을 볼 수 있습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   구독 유형</span></span></code></pre></div><p><strong>일반적인 구독 유형</strong>:</p><ul><li><code>plus</code>: 개인 Plus 구독</li><li><code>team</code>: 팀/조직 구독</li><li><code>pro</code>: Pro 구독</li></ul><p><strong>다음과 같이 보여야 합니다</strong>:</p><ul><li>계정 유형이 이메일 뒤의 괄호에 표시됨</li><li>다른 유형의 할당량은 다를 수 있음</li></ul><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><p>다음을 이해했는지 확인하세요:</p><table tabindex="0"><thead><tr><th>시나리오</th><th>보여야 하는 것</th></tr></thead><tbody><tr><td>메인 창 남음 60%</td><td>프로그레스 바가 약 60% 차고, <code>60% remaining</code> 표시</td></tr><tr><td>2.5시간 후 재설정</td><td><code>Resets in: 2h 30m</code> 표시</td></tr><tr><td>할당량 도달</td><td><code>Limit reached!</code> 표시</td></tr><tr><td>서브 창 있음</td><td>메인 창과 서브 창 각각 한 줄의 데이터</td></tr></tbody></table><h2 id="일반적인-실수" tabindex="-1">일반적인 실수 <a class="header-anchor" href="#일반적인-실수" aria-label="Permalink to &quot;일반적인 실수&quot;">​</a></h2><h3 id="❌-잘못된-작업-토큰-만료-후-새로고침하지-않음" tabindex="-1">❌ 잘못된 작업: 토큰 만료 후 새로고침하지 않음 <a class="header-anchor" href="#❌-잘못된-작업-토큰-만료-후-새로고침하지-않음" aria-label="Permalink to &quot;❌ 잘못된 작업: 토큰 만료 후 새로고침하지 않음&quot;">​</a></h3><p><strong>오류 증상</strong>: <code>⚠️ OAuth 인증이 만료되었습니다</code>(한국어) 또는 <code>⚠️ OAuth token expired</code>(영어) 표시</p><p><strong>원인</strong>: OAuth 토큰이 만료됨(서버에서 제어하는 구체적인 시간), 만료 후 할당량을 조회할 수 없음</p><p><strong>올바른 작업</strong>:</p><ol><li>OpenCode에서 OpenAI를 다시 로그인</li><li>토큰이 자동으로 새로고침됨</li><li>다시 <code>/mystatus</code> 실행하여 조회</li></ol><h3 id="❌-잘못된-작업-메인-창과-서브-창-혼동" tabindex="-1">❌ 잘못된 작업: 메인 창과 서브 창 혼동 <a class="header-anchor" href="#❌-잘못된-작업-메인-창과-서브-창-혼동" aria-label="Permalink to &quot;❌ 잘못된 작업: 메인 창과 서브 창 혼동&quot;">​</a></h3><p><strong>오류 증상</strong>: 하나의 창 할당량만 있는 줄 알고, 메인 창이 다 사용됐을 때 서브 창을 계속 사용</p><p><strong>원인</strong>: 두 창은 독립적인 할당량 풀</p><p><strong>올바른 작업</strong>:</p><ul><li>두 창의 각 재설정 시간에 주의</li><li>메인 창 재설정이 빠르고, 서브 창 재설정이 느림</li><li>합리적으로 사용하여 특정 창이 장기간 초과하지 않도록 함</li></ul><h3 id="❌-잘못된-작업-팀-계정-id-무시" tabindex="-1">❌ 잘못된 작업: 팀 계정 ID 무시 <a class="header-anchor" href="#❌-잘못된-작업-팀-계정-id-무시" aria-label="Permalink to &quot;❌ 잘못된 작업: 팀 계정 ID 무시&quot;">​</a></h3><p><strong>오류 증상</strong>: Team 구독이 자신의 사용 상황이 아닌 것을 표시</p><p><strong>원인</strong>: Team 구독은 팀 계정 ID를 전달해야 하며, 그렇지 않으면 기본 계정을 조회할 수 있음</p><p><strong>올바른 작업</strong>:</p><ul><li>OpenCode에 올바른 팀 계정으로 로그인했는지 확인</li><li>토큰에 자동으로 <code>chatgpt_account_id</code>가 포함됨</li></ul><h2 id="이번-수업-요약" tabindex="-1">이번 수업 요약 <a class="header-anchor" href="#이번-수업-요약" aria-label="Permalink to &quot;이번 수업 요약&quot;">​</a></h2><p>mystatus는 OpenAI 공식 API를 호출하여 할당량을 조회합니다:</p><ul><li>OAuth 인증 지원(Plus/Team/Pro)</li><li>메인 창 및 서브 창 표시(있다면)</li><li>프로그레스 바로 남은 할당량 시각화</li><li>카운트다운으로 재설정 시간 표시</li><li>토큰 만료 자동 감지</li></ul><h2 id="다음-수업-미리보기" tabindex="-1">다음 수업 미리보기 <a class="header-anchor" href="#다음-수업-미리보기" aria-label="Permalink to &quot;다음 수업 미리보기&quot;">​</a></h2><blockquote><p>다음 수업에서는 **<a href="./../zhipu-usage/">지푸 AI 및 Z.ai 할당량 조회</a>**를 학습합니다.</p><p>다음을 배우게 됩니다:</p><ul><li>5시간 Token 할당량은 무엇인가</li><li>MCP 월간 할당량을 어떻게 보는가</li><li>사용률이 80%를 초과할 때의 경고 표시</li></ul></blockquote><hr><h2 id="부록-소스코드-참조" tabindex="-1">부록: 소스코드 참조 <a class="header-anchor" href="#부록-소스코드-참조" aria-label="Permalink to &quot;부록: 소스코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스코드 위치 펼치기</strong></summary><blockquote><p>업데이트 날짜:2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>OpenAI 할당량 조회 엔트리</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>OpenAI API 호출</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>형식화 출력</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>JWT 토큰 파싱</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>사용자 이메일 추출</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>토큰 만료 확인</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>OpenAIAuthData 유형 정의</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>상수</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>: OpenAI 공식 할당량 조회 API</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>: OpenAI 할당량 조회의 메인 함수</li><li><code>fetchOpenAIUsage(accessToken)</code>: OpenAI API 호출</li><li><code>formatOpenAIUsage(data, email)</code>: 형식화 출력</li><li><code>parseJwt(token)</code>: JWT 토큰 파싱(비표준 라이브러리 구현)</li><li><code>getEmailFromJwt(token)</code>: 토큰에서 사용자 이메일 추출</li><li><code>getAccountIdFromJwt(token)</code>: 토큰에서 팀 계정 ID 추출</li></ul></details>`,70)])])}const b=e(i,[["render",n]]);export{u as __pageData,b as default};
